import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

const PALETTE = {
  amber: "#F59E0B",
  amberDeep: "#D97706",
  amberGlow: "rgba(245,158,11,0.15)",
  amberBorder: "rgba(245,158,11,0.35)",
  ember: "#EF4444",
  teal: "#14B8A6",
  violet: "#8B5CF6",
  rose: "#F43F5E",
  sky: "#0EA5E9",
  green: "#10B981",
  roundPalette: ["#F59E0B","#14B8A6","#8B5CF6","#F43F5E","#0EA5E9","#10B981"],
};

const glassCard = {
  background: "rgba(255,255,255,0.04)",
  backdropFilter: "blur(20px)",
  border: "1px solid rgba(255,255,255,0.08)",
  borderRadius: 16,
};

const injectStyles = () => {
  if (document.getElementById("wp-styles")) return;
  const style = document.createElement("style");
  style.id = "wp-styles";
  style.textContent = `
    @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;1,400&display=swap');

    .wp-root { font-family: 'DM Sans', sans-serif; }
    .wp-root * { box-sizing: border-box; }

    .wp-root ::-webkit-scrollbar { width: 4px; height: 4px; }
    .wp-root ::-webkit-scrollbar-track { background: transparent; }
    .wp-root ::-webkit-scrollbar-thumb { background: rgba(245,158,11,0.3); border-radius: 4px; }
    .wp-root ::-webkit-scrollbar-thumb:hover { background: rgba(245,158,11,0.5); }

    @keyframes wp-fadeIn { from { opacity:0; transform:translateY(8px); } to { opacity:1; transform:translateY(0); } }
    @keyframes wp-pulse { 0%,100% { transform:scale(1); } 50% { transform:scale(1.04); } }
    @keyframes wp-shimmer { 0% { background-position: -200% 0; } 100% { background-position: 200% 0; } }
    @keyframes wp-spin { from { transform:rotate(0deg); } to { transform:rotate(360deg); } }
    @keyframes wp-popIn { from { opacity:0; transform:scale(0.92) translateY(12px); } to { opacity:1; transform:scale(1) translateY(0); } }

    .wp-tile { transition: all 0.22s cubic-bezier(0.34,1.56,0.64,1); cursor:pointer; position:relative; overflow:hidden; }
    .wp-tile::before { content:''; position:absolute; inset:0; background: linear-gradient(135deg, rgba(245,158,11,0.08), transparent); opacity:0; transition:opacity 0.2s; }
    .wp-tile:hover { transform:translateY(-4px) scale(1.02); }
    .wp-tile:hover::before { opacity:1; }
    .wp-tile:active { transform:translateY(-1px) scale(0.99); }

    .wp-tile.available { border-color: rgba(20,184,166,0.35) !important; }
    .wp-tile.available:hover { border-color: rgba(20,184,166,0.7) !important; box-shadow: 0 12px 40px rgba(20,184,166,0.15), inset 0 1px 0 rgba(255,255,255,0.06); }
    .wp-tile.occupied { border-color: rgba(245,158,11,0.5) !important; }
    .wp-tile.occupied:hover { border-color: rgba(245,158,11,0.8) !important; box-shadow: 0 12px 40px rgba(245,158,11,0.2), inset 0 1px 0 rgba(255,255,255,0.06); }
    .wp-tile.reserved { border-color: rgba(139,92,246,0.45) !important; }
    .wp-tile.reserved:hover { border-color: rgba(139,92,246,0.8) !important; box-shadow: 0 12px 40px rgba(139,92,246,0.18), inset 0 1px 0 rgba(255,255,255,0.06); }

    .wp-menu-btn { transition: all 0.18s ease; cursor:pointer; border:none; position:relative; overflow:hidden; }
    .wp-menu-btn::after { content:''; position:absolute; inset:0; background:linear-gradient(135deg,rgba(245,158,11,0.12),transparent); opacity:0; transition:opacity 0.18s; }
    .wp-menu-btn:hover:not(:disabled) { transform:translateY(-3px); box-shadow: 0 8px 24px rgba(0,0,0,0.3); }
    .wp-menu-btn:hover:not(:disabled)::after { opacity:1; }
    .wp-menu-btn:active:not(:disabled) { transform:translateY(0); }
    .wp-menu-btn:disabled { opacity:0.35; cursor:not-allowed; }

    .wp-btn-primary { background: linear-gradient(135deg, #F59E0B, #D97706); border:none; border-radius:12px; color:#1a1000; font-weight:700; font-family:'DM Sans',sans-serif; padding:10px 20px; cursor:pointer; transition: all 0.2s ease; font-size:13px; letter-spacing:0.01em; }
    .wp-btn-primary:hover:not(:disabled) { background: linear-gradient(135deg,#FBBF24,#F59E0B); transform:translateY(-1px); box-shadow:0 8px 20px rgba(245,158,11,0.4); }
    .wp-btn-primary:active:not(:disabled) { transform:translateY(0); }
    .wp-btn-primary:disabled { opacity:0.5; cursor:not-allowed; }

    .wp-btn-ghost { background:rgba(255,255,255,0.06); border:1px solid rgba(255,255,255,0.1); border-radius:10px; color:rgba(255,255,255,0.7); font-family:'DM Sans',sans-serif; padding:8px 14px; cursor:pointer; transition:all 0.18s ease; font-size:12px; }
    .wp-btn-ghost:hover { background:rgba(255,255,255,0.1); border-color:rgba(255,255,255,0.2); color:#fff; }

    .wp-item-row { display:flex; align-items:center; justify-content:space-between; padding:10px 16px; border-bottom:1px solid rgba(255,255,255,0.04); transition:background 0.15s; }
    .wp-item-row:hover { background:rgba(255,255,255,0.03); }
    .wp-item-row:last-child { border-bottom:none; }

    .wp-remove-btn { width:22px; height:22px; border-radius:50%; background:rgba(239,68,68,0.12); border:1px solid rgba(239,68,68,0.25); color:rgba(239,68,68,0.8); cursor:pointer; display:flex; align-items:center; justify-content:center; font-size:14px; line-height:1; transition:all 0.15s; flex-shrink:0; }
    .wp-remove-btn:hover { background:rgba(239,68,68,0.25); border-color:rgba(239,68,68,0.5); color:#EF4444; transform:scale(1.1); }

    .wp-modal-overlay { position:fixed; inset:0; background:rgba(0,0,0,0.75); backdrop-filter:blur(8px); z-index:1000; display:flex; align-items:center; justify-content:center; animation:wp-fadeIn 0.2s ease; }
    .wp-modal { background:#141414; border:1px solid rgba(255,255,255,0.1); border-radius:24px; width:100%; max-width:460px; overflow:hidden; animation:wp-popIn 0.28s cubic-bezier(0.34,1.56,0.64,1); box-shadow:0 40px 80px rgba(0,0,0,0.6); }

    .wp-spinner { width:20px; height:20px; border:2px solid rgba(255,255,255,0.1); border-top-color:#F59E0B; border-radius:50%; animation:wp-spin 0.7s linear infinite; display:inline-block; }
    .wp-spinner-lg { width:36px; height:36px; border-width:3px; }

    .wp-cat-pill { display:inline-flex; align-items:center; gap:5px; padding:5px 12px; border-radius:20px; font-size:11px; font-weight:600; letter-spacing:0.04em; text-transform:uppercase; cursor:pointer; transition:all 0.18s; border:1px solid transparent; }

    .wp-badge { display:inline-flex; align-items:center; gap:4px; padding:3px 10px; border-radius:20px; font-size:11px; font-weight:600; }

    .wp-anim { animation:wp-fadeIn 0.3s ease both; }
    .wp-anim-delay-1 { animation-delay:0.05s; }
    .wp-anim-delay-2 { animation-delay:0.1s; }
    .wp-anim-delay-3 { animation-delay:0.15s; }

    .wp-send-btn { width:100%; padding:14px; border:none; border-radius:14px; font-size:15px; font-weight:800; font-family:'DM Sans',sans-serif; cursor:pointer; transition:all 0.22s cubic-bezier(0.34,1.56,0.64,1); letter-spacing:0.01em; }
    .wp-send-btn:hover:not(:disabled) { transform:translateY(-2px); }
    .wp-send-btn:active:not(:disabled) { transform:translateY(0) scale(0.99); }
    .wp-send-btn:disabled { opacity:0.5; cursor:not-allowed; transform:none; }

    .wp-status-dot { width:7px; height:7px; border-radius:50%; flex-shrink:0; }
    .wp-status-dot.available { background:#14B8A6; box-shadow:0 0 6px rgba(20,184,166,0.7); }
    .wp-status-dot.occupied { background:#F59E0B; box-shadow:0 0 6px rgba(245,158,11,0.7); animation:wp-pulse 2s infinite; }
    .wp-status-dot.reserved { background:#8B5CF6; box-shadow:0 0 6px rgba(139,92,246,0.7); }

    .wp-nav-btn { display:flex; align-items:center; gap:7px; padding:8px 14px; border-radius:10px; background:rgba(255,255,255,0.05); border:1px solid rgba(255,255,255,0.08); color:rgba(255,255,255,0.65); font-size:12px; font-weight:500; cursor:pointer; transition:all 0.18s; font-family:'DM Sans',sans-serif; }
    .wp-nav-btn:hover { background:rgba(255,255,255,0.09); color:#fff; border-color:rgba(255,255,255,0.15); }

    .wp-toggle { display:flex; align-items:center; gap:8px; padding:7px 14px; border-radius:10px; background:rgba(255,255,255,0.05); border:1px solid rgba(255,255,255,0.08); cursor:pointer; font-size:12px; color:rgba(255,255,255,0.6); font-family:'DM Sans',sans-serif; transition:all 0.18s; }
    .wp-toggle:hover { background:rgba(255,255,255,0.09); color:rgba(255,255,255,0.9); }

    .wp-section-label { font-family:'Syne',sans-serif; font-size:11px; font-weight:700; letter-spacing:0.08em; text-transform:uppercase; color:rgba(255,255,255,0.3); margin-bottom:10px; }
  `;
  document.head.appendChild(style);
};

export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [specials, setSpecials] = useState({});
  const [selectedTable, setSelectedTable] = useState(null);
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null);
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [view, setView] = useState("tables");
  const [confirmModal, setConfirmModal] = useState(false);
  const [confirming, setConfirming] = useState(false);
  const [activeOrderType, setActiveOrderType] = useState("table");
  const [taxSettings, setTaxSettings] = useState(null);
  const [activeCategory, setActiveCategory] = useState(null);
  const { user, logout, theme, toggleTheme } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  useEffect(() => { injectStyles(); }, []);

  const loadData = useCallback(async () => {
    try {
      const [t, m, s, tax] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
        API.get("/extras/specials"),
        API.get("/extras/tax-settings"),
      ]);
      setTables(t.data);
      const availMenu = m.data.filter(i => i.is_available);
      setMenu(availMenu);
      if (availMenu.length > 0) {
        const cats = [...new Set(availMenu.map(m => m.category))];
        setActiveCategory(cats[0]);
      }
      const sMap = {};
      s.data.forEach(sp => {
        sMap[sp.menu_id] = {
          ...sp,
          discounted_price: sp.discount_pct > 0
            ? Math.round(sp.price * (1 - sp.discount_pct / 100))
            : sp.price,
        };
      });
      setSpecials(sMap);
      setTaxSettings(tax.data);
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const loadTableRounds = useCallback(async (table) => {
    setRoundLoading(true);
    try {
      const allOrdersRes = await API.get(`/orders/table/${table.id}/all`);
      const orders = allOrdersRes.data || [];
      if (orders.length === 0) {
        setAllRounds([]); setDraftRoundIdx(null); setRoundLoading(false); return;
      }
      const roundsWithItems = await Promise.all(
        orders.map(async (order, idx) => {
          try {
            const detail = await API.get(`/orders/${order.id}`);
            return { order: detail.data.order, items: detail.data.items || [], roundNumber: idx + 1 };
          } catch { return { order, items: [], roundNumber: idx + 1 }; }
        })
      );
      setAllRounds(roundsWithItems);
      const draftIdx = roundsWithItems.findIndex(r => r.order.status === "draft");
      setDraftRoundIdx(draftIdx === -1 ? null : draftIdx);
    } catch {}
    setRoundLoading(false);
  }, []);

  const selectTable = async (table) => {
    setSelectedTable(table); setActiveOrderType("table"); setView("order");
    await loadTableRounds(table);
  };

  const refreshRound = async (roundIdx) => {
    const round = allRounds[roundIdx];
    if (!round) return;
    try {
      const detail = await API.get(`/orders/${round.order.id}`);
      setAllRounds(prev => {
        const updated = [...prev];
        updated[roundIdx] = { ...updated[roundIdx], order: detail.data.order, items: detail.data.items || [] };
        return updated;
      });
    } catch {}
  };

  const startOrder = async () => {
    if (!selectedTable) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0);
      await loadData();
    } catch (err) {
      if (err.response?.data?.order_id) await loadTableRounds(selectedTable);
    }
    setRoundLoading(false);
  };

  const startNewRound = async () => {
    if (!selectedTable) return;
    if (allRounds.some(r => r.order.status === "draft")) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table", addendum: true });
      const newRound = { order: res.data, items: [], roundNumber: allRounds.length + 1 };
      setAllRounds(prev => [...prev, newRound]);
      setDraftRoundIdx(allRounds.length);
      setTimeout(() => {
        summaryRef.current?.scrollTo({ top: summaryRef.current.scrollHeight, behavior: "smooth" });
      }, 200);
    } catch {}
    setRoundLoading(false);
  };

  const startTakeaway = async () => {
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { order_type: "takeaway" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0);
      setSelectedTable(null);
      setActiveOrderType("takeaway");
    } catch {}
    setRoundLoading(false);
    setView("order");
  };

  const addItem = async (menuItem) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    const special = specials[menuItem.id];
    const unit_price = special ? special.discounted_price : menuItem.price;
    try {
      await API.post(`/orders/${draftRound.order.id}/items`, { menu_id: menuItem.id, quantity: 1, unit_price });
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const removeItem = async (itemId) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    try {
      await API.delete(`/orders/${draftRound.order.id}/items/${itemId}`);
      await refreshRound(draftRoundIdx);
    } catch {}
  };

  const handleSendToKitchen = async () => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.items.length === 0) return;
    setConfirming(true);
    try {
      await API.put(`/orders/${draftRound.order.id}/confirm`);
      await refreshRound(draftRoundIdx);
      setDraftRoundIdx(null);
      setConfirmModal(false);
      await loadData();
    } catch {}
    setConfirming(false);
  };

  const handleLogout = async () => {
    try { await API.post("/auth/logout"); } catch {}
    logout(); navigate("/");
  };

  const goBack = () => {
    setView("tables"); setAllRounds([]); setDraftRoundIdx(null);
    setSelectedTable(null); loadData();
  };

  const categories = [...new Set(menu.map(m => m.category))];
  const catIcons = { food: "🍛", drink: "🥤", dessert: "🍰", snack: "🍿" };
  const catColors = { food: PALETTE.amber, drink: PALETTE.sky, dessert: PALETTE.rose, snack: PALETTE.teal };
  const roundColors = PALETTE.roundPalette;
  const combinedTotal = allRounds.reduce((sum, r) => sum + Number(r.order?.total || 0), 0);
  const taxRate = taxSettings ? (parseFloat(taxSettings.tax_rate) || 13) : 13;
  const taxEnabled = taxSettings ? taxSettings.tax_enabled !== false : false;
  const taxAmount = taxEnabled ? parseFloat((combinedTotal * taxRate / 100).toFixed(2)) : 0;
  const grandTotalWithTax = parseFloat((combinedTotal + taxAmount).toFixed(2));
  const hasSentRounds = allRounds.some(r => r.order.status !== "draft");
  const draftRound = draftRoundIdx !== null ? allRounds[draftRoundIdx] : null;
  const canAddItems = draftRound !== null && draftRound.order.status === "draft";

  const getRoundLabel = (idx) => ["Round 1","Round 2","Round 3","Round 4","Round 5","Round 6","Round 7","Round 8"][idx] || `Round ${idx+1}`;
  const getRoundOrdinal = (idx) => ["1st","2nd","3rd","4th","5th","6th","7th","8th"][idx] || `${idx+1}th`;

  const statusMeta = {
    available: { dot: "available", label: "Available", color: "#14B8A6" },
    occupied:  { dot: "occupied",  label: "Occupied",  color: "#F59E0B" },
    reserved:  { dot: "reserved",  label: "Reserved",  color: "#8B5CF6" },
  };

  const filteredMenu = activeCategory ? menu.filter(m => m.category === activeCategory) : menu;

  return (
    <div className="wp-root" style={{
      minHeight: "100vh",
      background: "#0D0D0D",
      backgroundImage: "radial-gradient(ellipse 80% 50% at 50% -20%, rgba(245,158,11,0.06) 0%, transparent 70%), radial-gradient(ellipse 60% 40% at 100% 100%, rgba(20,184,166,0.04) 0%, transparent 60%)",
      display: "flex",
