                      🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen
                    </button>
                    <div style={{ fontSize:10, color:"rgba(255,255,255,0.25)", textAlign:"center", marginTop:7 }}>
                      Only new items • No duplication
                    </div>
                  </div>
                )}

                {/* All sent */}
                {allRounds.length > 0 && draftRoundIdx === null && (
                  <div style={{ padding:"12px 16px", borderTop:"1px solid rgba(255,255,255,0.06)" }}>
                    <div style={{
                      background:"rgba(16,185,129,0.1)",
                      border:"1px solid rgba(16,185,129,0.2)",
                      borderRadius:10,
                      padding:"10px 14px",
                      textAlign:"center",
                      color:"#10B981",
                      fontWeight:600,
                      fontSize:13,
                      marginBottom: activeOrderType !== "takeaway" ? 10 : 0,
                    }}>
                      ✅ All rounds in kitchen
                    </div>
                    {activeOrderType !== "takeaway" && (
                      <button className="wp-btn-ghost" style={{ width:"100%", justifyContent:"center", display:"flex", gap:6 }} onClick={startNewRound}>
                        + Add {getRoundOrdinal(allRounds.length)} Round
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* ══════════════════════════════════════════════
          CONFIRM MODAL
      ══════════════════════════════════════════════ */}
      {confirmModal && draftRound && (
        <div className="wp-modal-overlay" onClick={() => setConfirmModal(false)}>
          <div className="wp-modal" onClick={e => e.stopPropagation()}>
            {/* Modal header */}
            <div style={{
              padding:"20px 24px 16px",
              borderBottom:"1px solid rgba(255,255,255,0.07)",
              display:"flex", justifyContent:"space-between", alignItems:"center",
            }}>
              <div>
                <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:17, letterSpacing:"-0.02em" }}>
                  Send to Kitchen
                </div>
                <div style={{ fontSize:12, color:"rgba(255,255,255,0.4)", marginTop:3 }}>
                  {activeOrderType === "takeaway" ? "📦 Takeaway" : `Table ${selectedTable?.table_number} · ${getRoundLabel(draftRoundIdx)}`}
                </div>
              </div>
              <button onClick={() => setConfirmModal(false)} style={{
                width:32, height:32, borderRadius:8,
                background:"rgba(255,255,255,0.06)", border:"1px solid rgba(255,255,255,0.08)",
                color:"rgba(255,255,255,0.5)", cursor:"pointer", fontSize:16,
                display:"flex", alignItems:"center", justifyContent:"center",
              }}>×</button>
            </div>

            {/* Modal body */}
            <div style={{ padding:"20px 24px" }}>
              {/* Emoji */}
              <div style={{
                width:60, height:60, borderRadius:16,
                background:"rgba(245,158,11,0.12)",
                border:"1px solid rgba(245,158,11,0.2)",
                display:"flex", alignItems:"center", justifyContent:"center",
                fontSize:28, margin:"0 auto 16px",
              }}>
                {activeOrderType === "takeaway" ? "📦" : draftRoundIdx === 0 ? "🍽️" : "➕"}
              </div>

              <div style={{ textAlign:"center", marginBottom:18 }}>
                <div style={{ fontWeight:600, fontSize:15 }}>
                  {activeOrderType === "takeaway"
                    ? "Send Takeaway to kitchen?"
                    : draftRoundIdx === 0
                    ? `Start Table ${selectedTable?.table_number}'s order?`
                    : `Send ${getRoundOrdinal(draftRoundIdx)} round for Table ${selectedTable?.table_number}?`}
                </div>
                {draftRoundIdx > 0 && (
                  <div style={{ fontSize:12, color:"rgba(255,255,255,0.4)", marginTop:4 }}>
                    Only these new items will go to kitchen.
                  </div>
                )}
              </div>

              <div style={{
                background:"rgba(255,255,255,0.03)",
                border:"1px solid rgba(255,255,255,0.07)",
                borderRadius:12,
                overflow:"hidden",
              }}>
                <div style={{ padding:"10px 14px", borderBottom:"1px solid rgba(255,255,255,0.06)" }}>
                  <div style={{ fontSize:10, fontWeight:700, color:"rgba(255,255,255,0.3)", textTransform:"uppercase", letterSpacing:"0.07em" }}>
                    {getRoundLabel(draftRoundIdx)} items
                  </div>
                </div>
                {draftRound.items.map((item, i) => (
                  <div key={i} style={{
                    padding:"8px 14px",
                    display:"flex", justifyContent:"space-between",
                    fontSize:13,
                    borderBottom: i < draftRound.items.length - 1 ? "1px solid rgba(255,255,255,0.04)" : "none",
                  }}>
                    <span>{item.name}</span>
                    <span style={{ color:"rgba(255,255,255,0.4)" }}>×{item.quantity}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Modal footer */}
            <div style={{
              padding:"16px 24px",
              borderTop:"1px solid rgba(255,255,255,0.07)",
              display:"flex", gap:10,
            }}>
              <button className="wp-btn-ghost" style={{ flex:1 }} onClick={() => setConfirmModal(false)}>
                Cancel
              </button>
              <button
                className="wp-btn-primary"
                style={{ flex:2, padding:"11px 0", fontSize:14 }}
                onClick={handleSendToKitchen}
                disabled={confirming}
              >
                {confirming ? (
                  <span style={{ display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
                    <div className="wp-spinner" />
                    Sending…
                  </span>
                ) : "✅ Confirm & Send"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
